@@ -0,0 +1,67 @@
+@layer utilities {
+  .animate-fade-in {
+    animation: fadeIn 0.8s ease-out forwards;
+  }
+
+  .animate-fade-in-up {
+    animation: fadeInUp 0.8s ease-out forwards;
+  }
+
+  .animate-pulse-slow {
+    animation: pulseSlow 4s ease-in-out infinite;
+  }
+
+  .animate-float {
+    animation: float 6s ease-in-out infinite;
+  }
+
+  .animation-delay-200 {
+    animation-delay: 0.2s;
+  }
+
+  .animation-delay-400 {
+    animation-delay: 0.4s;
+  }
+
+  .animation-delay-600 {
+    animation-delay: 0.6s;
+  }
+}
+
+@keyframes fadeIn {
+  from {
+    opacity: 0;
+  }
+  to {
+    opacity: 1;
+  }
+}
+
+@keyframes fadeInUp {
+  from {
+    opacity: 0;
+    transform: translateY(20px);
+  }
+  to {
+    opacity: 1;
+    transform: translateY(0);
+  }
+}
+
+@keyframes pulseSlow {
+  0%, 100% {
+    opacity: 0.4;
+  }
+  50% {
+    opacity: 0.8;
+  }
+}
+
+@keyframes float {
+  0%, 100% {
+    transform: translateY(0px);
+  }
+  50% {
+    transform: translateY(-10px);
+  }
+}

@@ -0,0 +1,57 @@
+@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');
+@import './variables.css';
+
+@layer base {
+  * {
+    @apply border-border;
+  }
+
+  html {
+    scroll-behavior: smooth;
+  }
+
+  body {
+    @apply bg-background text-foreground antialiased;
+    font-family: var(--font-display);
+  }
+
+  h1, h2, h3, h4, h5, h6 {
+    font-family: var(--font-display);
+    @apply font-medium tracking-tight;
+  }
+
+  code, pre {
+    font-family: var(--font-mono);
+  }
+
+  /* Custom Scrollbar Styling */
+  * {
+    scrollbar-width: thin;
+    scrollbar-color: hsl(var(--primary) / 0.3) hsl(var(--secondary) / 0.5);
+  }
+
+  *::-webkit-scrollbar {
+    width: 8px;
+    height: 8px;
+  }
+
+  *::-webkit-scrollbar-track {
+    background: hsl(var(--secondary) / 0.3);
+    border-radius: 4px;
+  }
+
+  *::-webkit-scrollbar-thumb {
+    background: hsl(var(--primary) / 0.3);
+    border-radius: 4px;
+    border: 2px solid transparent;
+    background-clip: padding-box;
+  }
+
+  *::-webkit-scrollbar-thumb:hover {
+    background: hsl(var(--primary) / 0.5);
+  }
+
+  *::-webkit-scrollbar-corner {
+    background: transparent;
+  }
+}

@@ -0,0 +1,35 @@
+@layer components {
+  .text-gradient-primary {
+    @apply bg-clip-text text-transparent;
+    background-image: linear-gradient(135deg, hsl(var(--primary)) 0%, hsl(185 70% 65%) 100%);
+  }
+
+  .text-gradient-accent {
+    @apply bg-clip-text text-transparent;
+    background-image: linear-gradient(135deg, hsl(var(--accent)) 0%, hsl(160 60% 55%) 100%);
+  }
+
+  .glow-primary {
+    box-shadow: var(--shadow-glow);
+  }
+
+  .glow-accent {
+    box-shadow: var(--shadow-glow-accent);
+  }
+
+  .card-elevated {
+    background: var(--gradient-card);
+    @apply border border-border/50;
+    box-shadow: var(--shadow-card);
+  }
+
+  .line-glow {
+    @apply relative;
+  }
+
+  .line-glow::after {
+    content: '';
+    @apply absolute inset-x-0 -bottom-px h-px;
+    background: linear-gradient(90deg, transparent, hsl(var(--primary) / 0.5), transparent);
+  }
+}

@@ -0,0 +1,65 @@
+:root {
+  /* Cognitum Dark Theme - Calm, Sparse, Sophisticated */
+  --background: 220 25% 6%;
+  --foreground: 210 20% 92%;
+
+  --card: 220 20% 10%;
+  --card-foreground: 210 20% 92%;
+
+  --popover: 220 20% 10%;
+  --popover-foreground: 210 20% 92%;
+
+  /* Primary - Cyan/Teal from chip imagery */
+  --primary: 185 80% 50%;
+  --primary-foreground: 220 25% 6%;
+
+  /* Secondary - Muted dark surface */
+  --secondary: 220 20% 14%;
+  --secondary-foreground: 210 20% 80%;
+
+  /* Accent - Green from logo dot */
+  --accent: 142 70% 50%;
+  --accent-foreground: 220 25% 6%;
+
+  --muted: 220 15% 15%;
+  --muted-foreground: 215 15% 55%;
+
+  --destructive: 0 65% 50%;
+  --destructive-foreground: 210 20% 92%;
+
+  --border: 220 15% 18%;
+  --input: 220 15% 18%;
+  --ring: 185 80% 50%;
+
+  --radius: 0.75rem;
+
+  /* Custom Cognitum tokens */
+  --glow-primary: 185 80% 50%;
+  --glow-accent: 142 70% 50%;
+  --surface-elevated: 220 20% 12%;
+  --surface-overlay: 220 20% 8%;
+
+  /* Gradients */
+  --gradient-hero: linear-gradient(135deg, hsl(220 25% 6%) 0%, hsl(220 20% 10%) 50%, hsl(200 25% 8%) 100%);
+  --gradient-card: linear-gradient(180deg, hsl(220 20% 12%) 0%, hsl(220 20% 8%) 100%);
+  --gradient-glow: radial-gradient(ellipse at center, hsl(185 80% 50% / 0.15) 0%, transparent 70%);
+
+  /* Shadows */
+  --shadow-glow: 0 0 60px -10px hsl(185 80% 50% / 0.3);
+  --shadow-glow-accent: 0 0 40px -10px hsl(142 70% 50% / 0.4);
+  --shadow-card: 0 8px 32px -8px hsl(220 25% 2% / 0.8);
+
+  /* Typography */
+  --font-display: 'Outfit', system-ui, sans-serif;
+  --font-mono: 'JetBrains Mono', monospace;
+
+  /* Sidebar */
+  --sidebar-background: 220 20% 8%;
+  --sidebar-foreground: 210 20% 85%;
+  --sidebar-primary: 185 80% 50%;
+  --sidebar-primary-foreground: 220 25% 6%;
+  --sidebar-accent: 220 15% 15%;
+  --sidebar-accent-foreground: 210 20% 85%;
+  --sidebar-border: 220 15% 18%;
+  --sidebar-ring: 185 80% 50%;
+}
